import matplotlib

sv = Statevector.from_label("01")

def is_fig(x):
    return isinstance(x, matplotlib.figure.Figure)

evidence = {}
proven = []

try:
    r = sv.qsphere()
    ok = is_fig(r)
    evidence["A"] = f"sv.qsphere() -> {type(r).__name__}; Figure={ok}"
    if ok:
        proven.append("A")
except Exception as e:
    evidence["A"] = f"raised {type(e).__name__}: {str(e)[:80]}"

try:
    from qiskit.visualization import plot_qsphere
